"use client";

import { useTheme } from "next-themes";
import { IconSunHighFilled, IconMoonStars } from "@tabler/icons-react";
import { Button } from "@/components/ui/button";
import { useState } from "react";

export function ThemeToggle() {
  const { setTheme } = useTheme();
  const [mode, setMode] = useState("dark");

  return (
    <div id="theme-toggle" role="theme-toggle">
      {mode == "light" ? (
        <Button
          id="light-mode"
          role="light-mode"
          variant="ghost"
          size="icon"
          onClick={() => {
            setMode("dark");
            setTheme("dark");
          }}
        >
          <IconSunHighFilled className="size-7 text-yellow-600" />
        </Button>
      ) : (
        <Button
          id="dark-mode"
          role="dark-mode"
          variant="ghost"
          size="icon"
          onClick={() => {
            setMode("light");
            setTheme("light");
          }}
        >
          <IconMoonStars className="size-7" />
        </Button>
      )}
      <span className="sr-only">Toggle theme</span>
    </div>
  );
}
